function solve(s) {
    // 1. Count frequencies of all characters
    const freqMap = new Map();
    for (const char of s) {
        freqMap.set(char, (freqMap.get(char) || 0) + 1);
    }

    // Helper function to find the mirror character
    const getMirror = (char) => {
        if (char >= 'a' && char <= 'z') {
            // For letters: 'a' -> 'z', 'b' -> 'y', etc.
            const charCode = char.charCodeAt(0);
            // 'a' is 97, 'z' is 122. Sum of codes should be 97 + 122 = 219
            const mirrorCharCode = 'a'.charCodeAt(0) + 'z'.charCodeAt(0) - charCode;
            return String.fromCharCode(mirrorCharCode);
        } else if (char >= '0' && char <= '9') {
            // For digits: '0' -> '9', '1' -> '8', etc.
            const charCode = char.charCodeAt(0);
            // '0' is 48, '9' is 57. Sum of codes should be 48 + 57 = 105
            const mirrorCharCode = '0'.charCodeAt(0) + '9'.charCodeAt(0) - charCode;
            return String.fromCharCode(mirrorCharCode);
        }
        return null; // Should not happen based on problem constraints
    };

    let totalAbsoluteDiff = 0;
    // Keep track of processed pairs (to avoid double counting)
    const processedPairs = new Set();

    // Iterate over all unique characters present in the string
    for (const char of freqMap.keys()) {
        if (processedPairs.has(char)) {
            continue;
        }

        const mirrorChar = getMirror(char);

        // Handle the case where the character is its own mirror (e.g., 'm'/'n' in some scenarios, 
        // or if the character type doesn't have a perfect match, though for the defined sets it should)
        if (char === mirrorChar) {
            // The problem statement implies we iterate over unique characters c, 
            // and if c=m, we calculate |freq(c) - freq(c)| = 0.
            // We process this once and move on.
            // Since we only add pairs (c, m) where c <= m lexicographically (or use a set), 
            // we need to ensure we count this correctly.
            totalAbsoluteDiff += 0; // |freq(c) - freq(c)| = 0
            processedPairs.add(char);
            continue;
        }

        // Ensure we only process the pair once. We enforce an ordering (e.g., lexicographical).
        // This prevents calculating for (c, m) and then again for (m, c).
        let c = char;
        let m = mirrorChar;

        if (c > m) {
            // Swap so we process the pair only when the lexicographically smaller element is 'c'
            c = mirrorChar;
            m = char;
        }

        if (processedPairs.has(c)) {
            continue; // Already processed as part of another pair
        }

        // Mark both as processed
        processedPairs.add(c);
        processedPairs.add(m);

        // Get frequencies. If a mirror character doesn't exist in s, its frequency is 0.
        const freqC = freqMap.get(c) || 0;
        const freqM = freqMap.get(m) || 0;

        // Calculate the absolute difference for this unique pair (c, m)
        const diff = Math.abs(freqC - freqM);

        totalAbsoluteDiff += diff;
    }

    return totalAbsoluteDiff;
}

